import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
    val totalNodes = c.toInt
    val parent = (0 to totalNodes).toArray
    val rank = new Array[Int](totalNodes + 1)

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    for (conn <- connections) {
        val u = conn(0).toInt
        val v = conn(1).toInt
        val ru = find(u)
        val rv = find(v)
        if (ru != rv) {
            if (rank(ru) < rank(rv)) {
                parent(ru) = rv
            } else if (rank(ru) > rank(rv)) {
                parent(rv) = ru
            } else {
                parent(rv) = ru
                rank(ru) += 1
            }
        }
    }

    val rootOf = new Array[Int](totalNodes + 1)
    for (i <- 1 to totalNodes) {
        rootOf(i) = find(i)
    }

    val onlineArr = Array.fill[Boolean](totalNodes + 1)(true)

    val compMap = mutable.Map[Int, mutable.TreeSet[Long]]()
    for (i <- 1 to totalNodes) {
        val root = rootOf(i)
        val set = compMap.getOrElseUpdate(root, mutable.TreeSet[Long]())
        set += i.toLong
    }

    val result = mutable.ArrayBuffer[Long]()
    for (q <- queries) {
        val typ = q(0)
        val node = q(1)
        val nodeInt = node.toInt
        if (typ == 1) {
            if (onlineArr(nodeInt)) {
                result += node
            } else {
                val root = rootOf(nodeInt)
                compMap.get(root) match {
                    case Some(set) =>
                        if (set.isEmpty) result += -1L
                        else result += set.head
                    case None => result += -1L
                }
            }
        } else if (typ == 2) {
            if (onlineArr(nodeInt)) {
                onlineArr(nodeInt) = false
                val root = rootOf(nodeInt)
                compMap.get(root).foreach { set =>
                    set -= node
                }
            }
        }
    }

    result.toArray
}
